const CATS = [
  { id: 22, name: "Videovigilancia" },
  { id: 37, name: "Control de Acceso" },
  { id: 30, name: "Energia" },
  { id: 38, name: "Deteccion de Fuego" },
  { id: 32, name: "Automatizacion e Intrusion" },
  { id: 25, name: "Radiocomunicacion" },
  { id: 26, name: "Redes" },
  { id: 27, name: "IoT / GPS / Telemetria" },
];
const MIN_DESCUENTO = 20;
const PAGES_PER_CAT = 5;
const TOP_PER_CAT = 13;

let token;
try {
  const tokenResp = await this.helpers.httpRequest({
    method: "POST",
    url: "https://developers.syscom.mx/oauth/token",
    headers: { "Content-Type": "application/x-www-form-urlencoded" },
    body: "client_id=zq2u2Zr1VFGam5IzAg5UolwmeSnsChP7&client_secret=thdUXtjZunSRT4IB1ascUHIZlWsA5PhtIL9mBWVz&grant_type=client_credentials"
  });
  token = tokenResp.access_token;
} catch(e) {
  return [{ json: { error: "Token fallo: " + e.message } }];
}

const allPromos = [];
for (const cat of CATS) {
  const catPromos = [];
  for (let page = 1; page <= PAGES_PER_CAT; page++) {
    try {
      const resp = await this.helpers.httpRequest({
        method: "GET",
        url: `https://developers.syscom.mx/api/v1/productos?categoria=${cat.id}&pagina=${page}&moneda=MXN`,
        headers: { "Authorization": "Bearer " + token },
        json: true,
        options: { timeout: 20000 }
      });
      const productos = resp.productos || [];
      if (productos.length === 0) break;
      for (const p of productos) {
        const lista = parseFloat(p.precios?.precio_lista || 0);
        const desc = parseFloat(p.precios?.precio_descuento || lista);
        if (lista > 0 && desc < lista) {
          const pct = Math.round((1 - desc / lista) * 100);
          if (pct >= MIN_DESCUENTO) {
            catPromos.push({
              sku: String(p.modelo || "").trim(),
              nombre: String(p.titulo || "Sin nombre"),
              marca: String(p.marca || ""),
              categoria: cat.name,
              precio_lista: lista,
              precio_promo: desc,
              descuento_pct: pct,
              ahorro: Math.round((lista - desc) * 100) / 100,
              existencia: p.total_existencia || 0,
              imagen: p.img_portada || ""
            });
          }
        }
      }
      if (catPromos.length >= TOP_PER_CAT * 4) break;
    } catch(e) {
      console.log(`Error cat ${cat.name} pag ${page}:`, e.message);
      break;
    }
  }
  catPromos.sort((a, b) => b.descuento_pct - a.descuento_pct);
  allPromos.push(...catPromos.slice(0, TOP_PER_CAT));
}

const totalPromos = allPromos.length;
const mejorDescuento = totalPromos > 0 ? Math.max(...allPromos.map(p => p.descuento_pct)) : 0;
const mayorAhorro = totalPromos > 0 ? Math.max(...allPromos.map(p => p.ahorro)) : 0;

return [{ json: { promos: allPromos, totalPromos, mejorDescuento, mayorAhorro, fecha: new Date().toLocaleDateString('es-MX', {weekday:'long', year:'numeric', month:'long', day:'numeric'}) } }];

const { promos, totalPromos, mejorDescuento, mayorAhorro, fecha } = $input.first().json;

if (!promos || promos.length === 0) {
  return [{ json: { subject: '[Syscom] Sin promos hoy', html: '<p>No se encontraron promociones hoy.</p>' } }];
}

const porCategoria = {};
for (const p of promos) {
  if (!porCategoria[p.categoria]) porCategoria[p.categoria] = [];
  porCategoria[p.categoria].push(p);
}

const catColors = {
  'Videovigilancia': '#1e40af',
  'Control de Acceso': '#065f46',
  'Energia': '#92400e',
  'Deteccion de Fuego': '#991b1b',
  'Automatizacion e Intrusion': '#4c1d95',
  'Radiocomunicacion': '#0e7490',
  'Redes': '#1d4ed8',
  'IoT / GPS / Telemetria': '#166534'
};

let sectionsHtml = '';
for (const [catName, items] of Object.entries(porCategoria)) {
  const color = catColors[catName] || '#374151';
  const cards = items.map(p => {
    const imgHtml = p.imagen
      ? `<img src="${p.imagen}" style="width:80px;height:80px;object-fit:contain;background:#f9fafb;border-radius:6px;" />`
      : `<div style="width:80px;height:80px;background:#e5e7eb;border-radius:6px;"></div>`;
    return `<tr>
      <td style="padding:10px 8px;border-bottom:1px solid #f3f4f6;vertical-align:middle;width:90px;text-align:center">${imgHtml}</td>
      <td style="padding:10px 8px;border-bottom:1px solid #f3f4f6;vertical-align:middle">
        <div style="font-weight:600;font-size:13px;color:#111827">${p.nombre.substring(0,80)}</div>
        <div style="font-size:11px;color:#6b7280">SKU: ${p.sku} | ${p.marca} | Stock: ${p.existencia}</div>
      </td>
      <td style="padding:10px 8px;border-bottom:1px solid #f3f4f6;vertical-align:middle;text-align:right;white-space:nowrap">
        <div style="font-size:11px;color:#9ca3af;text-decoration:line-through">Lista: $${p.precio_lista.toFixed(2)}</div>
        <div style="font-size:18px;font-weight:700;color:#dc2626">$${p.precio_promo.toFixed(2)}</div>
        <div style="display:inline-block;background:#dc2626;color:white;font-weight:700;font-size:12px;padding:2px 10px;border-radius:12px">-${p.descuento_pct}% OFF</div>
        <div style="font-size:11px;color:#059669;margin-top:3px">Ahorro: $${p.ahorro.toFixed(2)} MXN</div>
      </td>
    </tr>`;
  }).join('');

  sectionsHtml += `<div style="margin-bottom:24px">
    <div style="background:${color};color:white;padding:10px 16px;border-radius:8px 8px 0 0;font-weight:700;font-size:15px">${catName} - ${items.length} promo(s)</div>
    <table style="width:100%;border-collapse:collapse;background:white;border:1px solid #e5e7eb;border-top:0">${cards}</table>
  </div>`;
}

const html = `<html><body style="font-family:Arial,sans-serif;max-width:700px;margin:0 auto;padding:20px;background:#f8fafc">
<div style="background:linear-gradient(135deg,#dc2626,#991b1b);color:white;padding:24px 20px;border-radius:12px;margin-bottom:24px;text-align:center">
  <div style="font-size:28px;font-weight:800">SUPER PRECIO SYSCOM</div>
  <div style="font-size:14px;opacity:0.9;margin-top:4px">${fecha}</div>
  <div style="margin-top:16px;font-size:20px">${totalPromos} ofertas | Hasta -${mejorDescuento}% | Ahorro max $${Math.round(mayorAhorro).toLocaleString('es-MX')} MXN</div>
</div>
<p style="color:#374151;font-size:14px">Mejores promociones del dia (descuento mayor a 20%). Ver todas: <a href="https://www.syscom.mx/superprecio">syscom.mx/superprecio</a></p>
${sectionsHtml}
<p style="font-size:11px;color:#9ca3af;text-align:center">Ocean Tech - Reporte automatico - Precios MXN sin IVA</p>
</body></html>`;

const emoji = mejorDescuento >= 40 ? 'GRAN' : mejorDescuento >= 30 ? 'BUENA' : 'NUEVA';
return [{ json: { html, subject: `[${emoji} PROMO] Syscom: ${totalPromos} ofertas | Hasta -${mejorDescuento}% | ${fecha}` } }];

